const sendgrid = require('@sendgrid/mail');
const twilio = require('twilio');

const SENDGRID_API_KEY = 'SG.azure_demo_key_123';
const TWILIO_SID = 'AC1234567890abcdef';
const TWILIO_AUTH_TOKEN = 'your_twilio_auth_token'; // Replace with your Twilio Auth Token
const TWILIO_PHONE_NUMBER = 'your_twilio_phone_number'; // Replace with your Twilio phone number

sendgrid.setApiKey(SENDGRID_API_KEY);
const twilioClient = twilio(TWILIO_SID, TWILIO_AUTH_TOKEN);

module.exports = async function (context, req) {
    const { email, phone, message } = req.body;

    if (!validateInput(email, phone, message)) {
        context.res = {
            status: 400,
            body: "Invalid input"
        };
        return;
    }

    try {
        await sendEmail(email, message);
        await sendSMS(phone, message);
        
        context.res = {
            status: 200,
            body: "Email and SMS sent successfully"
        };
    } catch (error) {
        context.res = {
            status: 500,
            body: "Error sending message"
        };
    }
};

function validateInput(email, phone, message) {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    const phoneRegex = /^\+?[1-9]\d{1,14}$/; // E.164 format

    return emailRegex.test(email) && phoneRegex.test(phone) && typeof message === 'string' && message.length > 0;
}

async function sendEmail(email, message) {
    const msg = {
        to: email,
        from: 'your_verified_sender_email@example.com', // Replace with your verified sender email
        subject: 'Notification',
        text: message,
    };
    await sendgrid.send(msg);
}

async function sendSMS(phone, message) {
    await twilioClient.messages.create({
        body: message,
        from: TWILIO_PHONE_NUMBER,
        to: phone
    });
}